
-- Create blog_posts table
CREATE TABLE public.blog_posts (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  title TEXT NOT NULL,
  slug TEXT NOT NULL UNIQUE,
  date DATE NOT NULL DEFAULT CURRENT_DATE,
  excerpt TEXT NOT NULL DEFAULT '',
  content TEXT NOT NULL DEFAULT '',
  created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT now()
);

-- Enable RLS
ALTER TABLE public.blog_posts ENABLE ROW LEVEL SECURITY;

-- Anyone can read blog posts
CREATE POLICY "Anyone can read blog posts"
ON public.blog_posts
FOR SELECT
TO public
USING (true);

-- Only admin can insert
CREATE POLICY "Admin can insert blog posts"
ON public.blog_posts
FOR INSERT
TO authenticated
WITH CHECK ((SELECT auth.jwt() ->> 'email') = 'hello@pretaquiz.com');

-- Only admin can update
CREATE POLICY "Admin can update blog posts"
ON public.blog_posts
FOR UPDATE
TO authenticated
USING ((SELECT auth.jwt() ->> 'email') = 'hello@pretaquiz.com');

-- Only admin can delete
CREATE POLICY "Admin can delete blog posts"
ON public.blog_posts
FOR DELETE
TO authenticated
USING ((SELECT auth.jwt() ->> 'email') = 'hello@pretaquiz.com');

